import{_ as t,c as a,o as i,aq as r}from"./chunks/framework.D4KJmb9Q.js";const g=JSON.parse('{"title":"External plugins SDK","description":"Documentation on how to create an external Usagi manga source plugin.","frontmatter":{"title":"External plugins SDK","description":"Documentation on how to create an external Usagi manga source plugin.","footer":false},"headers":[],"relativePath":"dev/plugin-sdk/index.md","filePath":"dev/plugin-sdk/index.md","lastUpdated":1776346444000,"breadcrumbs":[{"text":"For developers","items":[{"text":"Contribute","link":"/dev/contribute/"},{"text":"Plugin package format","link":"/dev/parsers-library/"},{"text":"Synchronization server","link":"/dev/sync-server/"},{"text":"External plugins SDK","link":"/dev/plugin-sdk/"}]},{"text":"External plugins SDK","link":"/dev/plugin-sdk/"}]}'),o={name:"dev/plugin-sdk/index.md"};function l(s,e,n,c,d,p){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="external-plugins-sdk" tabindex="-1">External plugins SDK <a class="header-anchor" href="#external-plugins-sdk" aria-label="Permalink to &quot;External plugins SDK&quot;">​</a></h1><p>Usagi loads source providers from external plugin files (<code>.jar</code>). This page outlines the current packaging and release workflow for plugin authors.</p><h2 id="what-to-ship" tabindex="-1">What to ship <a class="header-anchor" href="#what-to-ship" aria-label="Permalink to &quot;What to ship&quot;">​</a></h2><ul><li>Build your plugin as a <code>.jar</code>.</li><li>Ensure the plugin exposes compatible parser entry points for the current Usagi release.</li><li>Keep source keys stable between updates.</li></ul><h2 id="release-workflow" tabindex="-1">Release workflow <a class="header-anchor" href="#release-workflow" aria-label="Permalink to &quot;Release workflow&quot;">​</a></h2><ol><li>Publish your plugin code in a GitHub repository.</li><li>Create a release and attach the plugin <code>.jar</code> asset.</li><li>Make sure the <strong>latest release</strong> contains a valid <code>.jar</code> so users can import via GitHub directly in Usagi.</li></ol><h2 id="user-import-flow-for-testing" tabindex="-1">User import flow (for testing) <a class="header-anchor" href="#user-import-flow-for-testing" aria-label="Permalink to &quot;User import flow (for testing)&quot;">​</a></h2><ol><li>Open <strong>Settings</strong> -&gt; <strong>Sources</strong> -&gt; <strong>Manage plugins</strong> in Usagi.</li><li>Tap <strong>+</strong>.</li><li>Use <strong>Import from GitHub</strong> (<code>owner/repository</code>) or <strong>Import from local storage</strong>.</li><li>Confirm sources appear in <strong>Sources Catalog</strong> and can be enabled.</li></ol><h2 id="compatibility-checklist" tabindex="-1">Compatibility checklist <a class="header-anchor" href="#compatibility-checklist" aria-label="Permalink to &quot;Compatibility checklist&quot;">​</a></h2><ul><li>Test with the latest app build before publishing.</li><li>Validate browse/search/details/chapters/pages on at least one source in your plugin.</li><li>If import fails, confirm the release asset is a <code>.jar</code> and not blocked by packaging/signing issues.</li></ul>',10)])])}const h=t(o,[["render",l]]);export{g as __pageData,h as default};
